const body = $input.first().json.body || $input.first().json;

// Normaliza telefone: aceita qualquer formato e padroniza pra 5567XXXXXXXXX
const rawPhone = String(body.phone || '').replace(/\D/g, '');
const phone = rawPhone.startsWith('55') ? rawPhone : '55' + rawPhone;

// Gera SHA256 do telefone
const crypto = require('crypto');
const phoneHash = crypto.createHash('sha256').update(phone).digest('hex');

// SHA256 do email (se vier)
let emailHash = null;
if (body.email) {
  emailHash = crypto.createHash('sha256').update(body.email.toLowerCase().trim()).digest('hex');
}

// SHA256 do nome (se vier)
let fnHash = null;
if (body.first_name) {
  fnHash = crypto.createHash('sha256').update(body.first_name.toLowerCase().trim()).digest('hex');
}

// event_id único para deduplicação
const eventId = body.event_id || `lumina_${Date.now()}_${Math.random().toString(36).slice(2,8)}`;

return [{
  json: {
    phone_hash: phoneHash,
    email_hash: emailHash,
    fn_hash: fnHash,
    event_id: eventId,
    value: body.value || 29.00,
    currency: body.currency || 'BRL',
    content_name: body.content_name || 'Ensaio Fotografico IA',
    event_time: Math.floor(Date.now() / 1000)
  }
}];
